import React from 'react';
import { motion } from 'framer-motion';

const Logo: React.FC<{ size?: 'small' | 'medium' | 'large' }> = ({ size = 'medium' }) => {
  const sizeClasses = {
    small: 'w-8 h-8',
    medium: 'w-12 h-12',
    large: 'w-16 h-16'
  };

  return (
    <motion.div
      className={`relative ${sizeClasses[size]}`}
      initial={{ rotate: 0 }}
      animate={{ rotate: 360 }}
      transition={{ duration: 20, repeat: Infinity, ease: "linear" }}
    >
      <svg viewBox="0 0 120 80" className="w-full h-full">
        {/* House outlines in background */}
        <motion.g opacity="0.3">
          {/* Left house outline */}
          <motion.path
            d="M15 65 L15 35 L30 25 L45 35 L45 65 Z"
            stroke="#666666"
            strokeWidth="1"
            fill="none"
            initial={{ pathLength: 0 }}
            animate={{ pathLength: 1 }}
            transition={{ duration: 2, delay: 0.5, ease: "easeInOut" }}
          />
          {/* Right house outline */}
          <motion.path
            d="M75 65 L75 35 L90 25 L105 35 L105 65 Z"
            stroke="#666666"
            strokeWidth="1"
            fill="none"
            initial={{ pathLength: 0 }}
            animate={{ pathLength: 1 }}
            transition={{ duration: 2, delay: 0.7, ease: "easeInOut" }}
          />
        </motion.g>
        
        {/* First M - Black */}
        <motion.path
          d="M25 60 L25 30 L35 45 L45 30 L45 60 M35 45 L35 60"
          stroke="#000000"
          strokeWidth="4"
          fill="none"
          strokeLinecap="round"
          strokeLinejoin="round"
          initial={{ pathLength: 0, opacity: 0 }}
          animate={{ pathLength: 1, opacity: 1 }}
          transition={{ duration: 1.5, delay: 0.3, ease: "easeInOut" }}
        />
        
        {/* Second M - Brown */}
        <motion.path
          d="M50 60 L50 30 L60 45 L70 30 L70 60 M60 45 L60 60"
          stroke="#8B4513"
          strokeWidth="4"
          fill="none"
          strokeLinecap="round"
          strokeLinejoin="round"
          initial={{ pathLength: 0, opacity: 0 }}
          animate={{ pathLength: 1, opacity: 1 }}
          transition={{ duration: 1.5, delay: 0.6, ease: "easeInOut" }}
        />
        
        {/* MM SPACES text */}
        <motion.text
          x="60"
          y="75"
          fontSize="8"
          fontWeight="500"
          fill="#333333"
          textAnchor="middle"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 1, delay: 0.9, ease: "easeOut" }}
        >
          MM SPACES
        </motion.text>
      </svg>
    </motion.div>
  );
};

export default Logo;
